Tool.Code:
import hashlib import json
def validate_ssot_lock(ssot_object: dict, stored_checksum: str) -> dict: """ Verify SSOT object integrity by comparing checksums. Deterministic - no LLM needed. """ current_checksum = hashlib.sha256( json.dumps(ssot_object, sort_keys=True).encode() ).hexdigest()
is_valid = current_checksum == stored_checksum
return { "passed": is_valid, "stored_checksum": stored_checksum, "current_checksum": current_checksum, "drift_detected": not is_valid }

def check_circuit_breaker(fix_counts: dict, max_loops: int = 3) -> dict:
    """
    Check if any MMA dimension has exceeded FIX loop limit.
    Deterministic - no LLM needed.
    """
    tripped_dimensions = []

    for dimension, count in fix_counts.items():
        if count >= max_loops:
            tripped_dimensions.append({
                "dimension": dimension,
                "count": count,
                "max": max_loops
            })

    return {
        "breaker_tripped": len(tripped_dimensions) > 0,
        "tripped_dimensions": tripped_dimensions,
        "recommendation": "escalate" if tripped_dimensions else "continue"
    }

import hashlib
import json

def generate_checksum(ssot_object: dict) -> str:
    """
    Generate deterministic checksum for SSOT object.
    Used for locking and drift detection.
    """
    return hashlib.sha256(
        json.dumps(ssot_object, sort_keys=True).encode()
    ).hexdigest()
